+// ============================================================================
+// Retry Logic
+// ============================================================================
+
+/**
+ * Sleep for a given duration.
+ */
+function sleep(ms: number): Promise<void> {
+  return new Promise((resolve) => setTimeout(resolve, ms));
+}
+
+/**
+ * Calculate delay for retry with exponential backoff.
+ */
+function calculateRetryDelay(
+  attemptNumber: number,
+  policy: RetryPolicy,
+): number {
+  const multiplier = policy.multiplier ?? 2;
+  const delay = policy.initialDelay * Math.pow(multiplier, attemptNumber);
+  // Add jitter (10% random variation)
+  const jitter = delay * 0.1 * Math.random();
+  return Math.min(delay + jitter, policy.maxDelay);
+}
+
+/**
+ * Execute a function with retry logic.
+ */
+async function withRetry<T>(
+  fn: () => Promise<T>,
+  policy: RetryPolicy,
+  isRetryable: (error: unknown) => boolean,
+  signal?: AbortSignal,
+): Promise<{ result: T; retryCount: number }> {
+  let lastError: unknown;
+  let retryCount = 0;
+
+  for (let attempt = 0; attempt <= policy.maxRetries; attempt++) {
+    if (signal?.aborted) {
+      throw new Error("Execution cancelled");
+    }
+
+    try {
+      const result = await fn();
+      return { result, retryCount };
+    } catch (error) {
+      lastError = error;
+
+      // Check if we should retry
+      if (attempt < policy.maxRetries && isRetryable(error)) {
+        retryCount++;
+        const delay = calculateRetryDelay(attempt, policy);
+        await sleep(delay);
+      } else {
+        throw error;
+      }
+    }
+  }
+
+  throw lastError;
+}
