+// ============================================================================
+// Testing Utilities
+// ============================================================================
+
+/**
+ * Clear all pipelines and runs (for testing).
+ */
+export function clearAll(): void {
+  pipelines.clear();
+  runs.clear();
+  pendingApprovals.clear();
+  for (const controller of activeRunControllers.values()) {
+    controller.abort();
+  }
+  activeRunControllers.clear();
+}
